   294→        // Render heatmap
   295→        function renderHeatmap() {
   296→            const canvas = document.getElementById('heatmapCanvas');
   297→            const ctx = canvas.getContext('2d');
   298→            const container = canvas.parentElement;
   299→
   300→            canvas.width = container.clientWidth;
   301→            canvas.height = container.clientHeight;
   302→
   303→            const w = canvas.width;
   304→            const h = canvas.height;
   305→            const cellW = 6;
   306→            const cellH = ROW_HEIGHT;
   307→
   308→            // Create concentrated hotspots like in the design
   309→            // The design shows dark red "blob" concentrations, especially on the right side
   310→            const hotspots = [
   311→                // Right side concentration (main maintenance peaks)
   312→                { x: 0.70, y: 0.20, radius: 0.12, intensity: 1.0 },
   313→                { x: 0.75, y: 0.35, radius: 0.15, intensity: 1.0 },
   314→                { x: 0.82, y: 0.50, radius: 0.18, intensity: 1.0 },
   315→                { x: 0.78, y: 0.65, radius: 0.14, intensity: 1.0 },
   316→                { x: 0.85, y: 0.80, radius: 0.12, intensity: 0.9 },
   317→                // Center area (secondary peaks)
   318→                { x: 0.45, y: 0.30, radius: 0.08, intensity: 0.6 },
   319→                { x: 0.50, y: 0.55, radius: 0.10, intensity: 0.5 },
   320→                { x: 0.40, y: 0.75, radius: 0.07, intensity: 0.5 },
   321→                // Scattered smaller spots
   322→                { x: 0.25, y: 0.40, radius: 0.05, intensity: 0.3 },
   323→                { x: 0.30, y: 0.60, radius: 0.06, intensity: 0.35 },
   324→                { x: 0.60, y: 0.25, radius: 0.06, intensity: 0.4 },
   325→            ];
   326→
   327→            // Noise function for texture
   328→            function noise(x, y, seed) {
   329→                const n = Math.sin(x * 12.9898 + y * 78.233 + seed) * 43758.5453;
   330→                return n - Math.floor(n);
   331→            }
   332→
   333→            // Gaussian function for blob falloff
   334→            function gaussian(x, y, cx, cy, radius) {
   335→                const dx = x - cx;
   336→                const dy = y - cy;
   337→                const d2 = (dx * dx + dy * dy) / (radius * radius);
   338→                return Math.exp(-d2 * 2.5);
   339→            }
   340→
   341→            // Color ramp: Yellow → Orange → Dark Red
   342→            function getHeatColor(value) {
   343→                value = Math.min(1, Math.max(0, value));
   344→
   345→                if (value < 0.25) {
   346→                    // Light yellow to yellow-orange
   347→                    const t = value / 0.25;
   348→                    return `rgb(255, ${Math.floor(248 - t * 30)}, ${Math.floor(200 - t * 120)})`;
   349→                } else if (value < 0.5) {
   350→                    // Yellow-orange to orange
   351→                    const t = (value - 0.25) / 0.25;
   352→                    return `rgb(255, ${Math.floor(218 - t * 60)}, ${Math.floor(80 - t * 50)})`;
   353→                } else if (value < 0.75) {
   354→                    // Orange to dark orange-red
   355→                    const t = (value - 0.5) / 0.25;
   356→                    return `rgb(${Math.floor(255 - t * 40)}, ${Math.floor(158 - t * 80)}, ${Math.floor(30 - t * 20)})`;
   357→                } else {
   358→                    // Dark orange-red to dark red
   359→                    const t = (value - 0.75) / 0.25;
   360→                    return `rgb(${Math.floor(215 - t * 55)}, ${Math.floor(78 - t * 50)}, ${Math.floor(10 + t * 20)})`;
   361→                }
   362→            }
   363→
   364→            // Render each cell
   365→            for (let x = 0; x < w; x += cellW) {
   366→                for (let y = 0; y < h; y += cellH) {
   367→                    const nx = x / w;
   368→                    const ny = y / h;
   369→
   370→                    // Base value with some noise texture
   371→                    let value = noise(nx * 20, ny * 15, 42) * 0.15;
   372→
   373→                    // Add gaussian blob influence from each hotspot
   374→                    hotspots.forEach(hs => {
   375→                        const blobValue = gaussian(nx, ny, hs.x, hs.y, hs.radius) * hs.intensity;
   376→                        value += blobValue * 0.85;
   377→                    });
   378→
   379→                    // Small random noise for texture
   380→                    value += noise(x * 0.3, y * 0.3, 123) * 0.05;
   381→
   382→                    ctx.fillStyle = getHeatColor(value);
   383→                    ctx.fillRect(x, y, cellW - 0.5, cellH - 0.5);
   384→                }
   385→            }
   386→
   387→            // Update selection overlay position
   388→            const overlay = document.getElementById('selectionOverlay');
   389→            overlay.style.left = (w * 0.65) + 'px';
   390→            overlay.style.top = '10px';
   391→            overlay.style.width = (w * 0.30) + 'px';
   392→            overlay.style.height = (h - 20) + 'px';
   393→        }
