   404→            const h = canvas.height;
   405→
   406→            // Simple minimap representation
   407→            for (let x = 0; x < w; x++) {
   408→                const intensity = Math.sin(x / w * Math.PI * 4) * 0.3 +
   409→                                 Math.random() * 0.2 +
   410→                                 (x / w > 0.6 ? 0.4 : 0.1);
   411→
   412→                const barHeight = intensity * h;
   413→
   414→                ctx.fillStyle = intensity > 0.5 ? '#dc2626' : intensity > 0.3 ? '#f59e0b' : '#fbbf24';
   415→                ctx.fillRect(x, h - barHeight, 1, barHeight);
   416→            }
   417→        }
