   312→            const cells = [];
   313→
   314→            for (let i = 0; i < MONTHS; i++) {
   315→                const monthIndex = i % 12;
   316→                const year = START_YEAR + Math.floor(i / 12);
   317→                const isYearMarker = monthIndex === 0;
   318→
   319→                cells.push(`<div class="timeline-month${isYearMarker ? ' year-marker' : ''}">${isYearMarker ? year : monthNames[monthIndex]}</div>`);
   320→            }
