   325→        // Render DNA strips
   326→        function renderDNA() {
   327→            const canvas = document.getElementById('dnaCanvas');
   328→            const ctx = canvas.getContext('2d');
   329→            const container = canvas.parentElement;
   330→
   331→            canvas.width = container.clientWidth;
   332→            canvas.height = container.clientHeight;
   333→
   334→            const w = canvas.width;
   335→            const h = canvas.height;
   336→
   337→            // Background
   338→            ctx.fillStyle = '#f8f9fa';
   339→            ctx.fillRect(0, 0, w, h);
   340→
   341→            // Task parameters
   342→            const taskHeight = 12;
   343→            const taskGap = 4;
   344→            const angle = -25 * Math.PI / 180;
   345→
   346→            // Color palette for tasks
   347→            const colors = {
   348→                blue: { fill: '#3b82f6', stroke: '#1d4ed8' },      // Routine maintenance
   349→                orange: { fill: '#f59e0b', stroke: '#d97706' },    // Overhaul
   350→                gray: { fill: '#9ca3af', stroke: '#6b7280' }       // Inspection
   351→            };
   352→
   353→            // Generate task data
   354→            const tasks = [];
   355→            for (let row = 0; row < TRAIN_COUNT; row++) {
   356→                const y = row * ROW_HEIGHT;
   357→
   358→                // Generate tasks for this train
   359→                let x = Math.random() * 50; // Random start offset
   360→
   361→                while (x < w + 100) {
   362→                    const taskWidth = 30 + Math.random() * 50;
   363→                    const colorType = Math.random() < 0.6 ? 'blue' : (Math.random() < 0.7 ? 'orange' : 'gray');
   364→
   365→                    tasks.push({
   366→                        x: x,
   367→                        y: y,
   368→                        width: taskWidth,
   369→                        color: colors[colorType],
   370→                        row: row
   371→                    });
   372→
   373→                    x += taskWidth + 10 + Math.random() * 30;
   374→                }
   375→            }
   376→
   377→            // Draw tasks with diagonal pattern
   378→            tasks.forEach(task => {
   379→                ctx.save();
