   388→                const w = task.width;
   389→                const h = taskHeight;
   390→                const r = 3;
   391→
   392→                ctx.beginPath();
   393→                ctx.moveTo(r, 0);
   394→                ctx.lineTo(w - r, 0);
   395→                ctx.quadraticCurveTo(w, 0, w, r);
   396→                ctx.lineTo(w, h - r);
   397→                ctx.quadraticCurveTo(w, h, w - r, h);
   398→                ctx.lineTo(r, h);
   399→                ctx.quadraticCurveTo(0, h, 0, h - r);
   400→                ctx.lineTo(0, r);
   401→                ctx.quadraticCurveTo(0, 0, r, 0);
   402→                ctx.closePath();
   403→
   404→                // Fill with gradient
   405→                const gradient = ctx.createLinearGradient(0, 0, w, h);
   406→                gradient.addColorStop(0, task.color.fill);
   407→                gradient.addColorStop(1, task.color.stroke);
   408→                ctx.fillStyle = gradient;
   409→                ctx.fill();
   410→
   411→                // Stroke
   412→                ctx.strokeStyle = task.color.stroke;
   413→                ctx.lineWidth = 1;
   414→                ctx.stroke();
   415→
   416→                ctx.restore();
   417→            });
   418→
   419→            // Selection highlight
   420→            const highlight = document.getElementById('selectionHighlight');
   421→            highlight.style.left = (w * 0.35) + 'px';
   422→            highlight.style.top = '0';
   423→            highlight.style.width = (w * 0.15) + 'px';
   424→            highlight.style.height = h + 'px';
   425→        }
   426→
   427→        // Render minimap
   428→        function renderScrubber() {
   429→            const canvas = document.getElementById('scrubberMinimap');
   430→            const ctx = canvas.getContext('2d');
   431→
   432→            canvas.width = canvas.parentElement.clientWidth;
   433→            canvas.height = 24;
   434→
   435→            const w = canvas.width;
   436→            const h = canvas.height;
   437→
   438→            // Draw mini DNA pattern
   439→            for (let x = 0; x < w; x += 3) {
   440→                for (let y = 2; y < h - 2; y += 4) {
   441→                    if (Math.random() > 0.4) {
   442→                        ctx.fillStyle = Math.random() > 0.5 ? '#3b82f6' : '#f59e0b';
   443→                        ctx.fillRect(x + (y * 0.2), y, 2, 3);
   444→                    }
   445→                }
   446→            }
   447→        }
   448→
   449→        // Tooltip handling
   450→        const canvas = document.getElementById('dnaCanvas');
   451→        const tooltip = document.getElementById('tooltip');
   452→
   453→        canvas.addEventListener('mousemove', (e) => {
   454→            const rect = canvas.getBoundingClientRect();
   455→            const x = e.clientX - rect.left;
   456→            const y = e.clientY - rect.top;
   457→
   458→            // Show tooltip near cursor
   459→            tooltip.style.left = (e.clientX + 15) + 'px';
   460→            tooltip.style.top = (e.clientY - 30) + 'px';
   461→
   462→            // Simulate task detection
   463→            const row = Math.floor(y / ROW_HEIGHT);
   464→            const trainType = row < 50 ? 'ALT' : 'KNK';
   465→            const trainNum = String((row % 50) + 1).padStart(3, '0');
   466→
   467→            const taskTypes = ['A-Check', 'B-Check', 'C-Check', 'D-Overhaul'];
   468→            const taskType = taskTypes[Math.floor(Math.random() * 4)];
   469→
   470→            document.getElementById('tooltipTitle').textContent = `${taskType} | ${trainType}-${trainNum}`;
   471→            tooltip.classList.add('visible');
   472→        });
   473→
   474→        canvas.addEventListener('mouseleave', () => {
   475→            tooltip.classList.remove('visible');
   476→        });
   477→
   478→        // Initialize
   479→        generateSidebar();
   480→        generateTimeline();
   481→        renderDNA();
   482→        renderScrubber();
   483→
   484→        window.addEventListener('resize', () => {
   485→            renderDNA();
   486→            renderScrubber();
   487→        });
   488→    </script>
