   433→    <script>
   434→        const TRAIN_COUNT = 20;
   435→        const DAYS = 42; // 6 weeks
   436→        const ROW_HEIGHT = 50;
   437→        const DAY_WIDTH = 80;
   438→        const START_DATE = new Date(2032, 0, 12); // Jan 12, 2032 (Monday)
   439→
   440→        // Task types
   441→        const TASK_TYPES = [
   442→            { name: 'A-Check', type: 'maintenance', duration: [1, 1], manHours: 8 },
   443→            { name: 'B-Check', type: 'maintenance', duration: [1, 2], manHours: 32 },
   444→            { name: 'C-Check', type: 'overhaul', duration: [3, 5], manHours: 160 },
   445→            { name: 'D-Overhaul', type: 'overhaul', duration: [15, 20], manHours: 1200 },
   446→            { name: 'Safety Inspection', type: 'inspection', duration: [1, 1], manHours: 4 },
   447→            { name: 'Wheel Profile', type: 'inspection', duration: [1, 2], manHours: 8 }
   448→        ];
   449→
   450→        // Generate train data
   451→        const trains = [];
   452→        for (let i = 0; i < TRAIN_COUNT; i++) {
   453→            const type = i < 12 ? 'ALT' : 'KNK';
   454→            const num = String((i % 12) + 1).padStart(3, '0');
   455→            trains.push(`${type}-${num}`);
   456→        }
   457→
   458→        // Generate tasks
   459→        const tasks = [];
   460→        let taskId = 0;
   461→
   462→        for (let row = 0; row < TRAIN_COUNT; row++) {
   463→            let dayOffset = Math.floor(Math.random() * 5);
   464→
   465→            while (dayOffset < DAYS - 3) {
   466→                const taskType = TASK_TYPES[Math.floor(Math.random() * TASK_TYPES.length)];
   467→                const duration = taskType.duration[0] + Math.floor(Math.random() * (taskType.duration[1] - taskType.duration[0] + 1));
   468→
   469→                // Random conflict (10% chance)
   470→                const hasConflict = Math.random() < 0.1;
   471→
   472→                tasks.push({
   473→                    id: taskId++,
   474→                    trainIndex: row,
   475→                    trainId: trains[row],
   476→                    startDay: dayOffset,
   477→                    duration: duration,
   478→                    taskType: taskType,
   479→                    conflict: hasConflict,
   480→                    dependencies: []
   481→                });
   482→
   483→                dayOffset += duration + 2 + Math.floor(Math.random() * 5);
   484→            }
   485→        }
   486→
   487→        // Add some dependencies
   488→        for (let i = 1; i < tasks.length; i++) {
   489→            if (Math.random() < 0.15 && i > 0) {
   490→                // Find a task in a different row that ends before this one starts
   491→                const candidates = tasks.filter((t, idx) =>
   492→                    idx < i &&
   493→                    t.trainIndex !== tasks[i].trainIndex &&
   494→                    t.startDay + t.duration < tasks[i].startDay
   495→                );
   496→                if (candidates.length > 0) {
   497→                    const dep = candidates[Math.floor(Math.random() * candidates.length)];
   498→                    tasks[i].dependencies.push(dep.id);
   499→                }
   500→            }
   501→        }
   502→
   503→        // Generate sidebar
   504→        function generateSidebar() {
   505→            const list = document.getElementById('sidebarList');
   506→            list.innerHTML = trains.map(t => `<div class="sidebar-item">${t}</div>`).join('');
   507→        }
   508→
   509→        // Generate timeline
   510→        function generateTimeline() {
   511→            const header = document.getElementById('timelineHeader');
   512→            const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   513→            const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
   514→
   515→            let html = '';
   516→
   517→            for (let i = 0; i < DAYS; i++) {
   518→                const date = new Date(START_DATE);
   519→                date.setDate(date.getDate() + i);
   520→
   521→                const dayOfWeek = date.getDay();
   522→                const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
   523→                const isToday = i === 5; // Mark day 5 as "today" for demo
   524→
   525→                let classes = 'timeline-day';
   526→                if (isWeekend) classes += ' weekend';
   527→                if (isToday) classes += ' today';
   528→
   529→                html += `
   530→                    <div class="${classes}">
   531→                        <span class="day-name">${dayNames[dayOfWeek]}</span>
   532→                        <span>${monthNames[date.getMonth()]} ${date.getDate()}</span>
   533→                    </div>
   534→                `;
   535→            }
   536→
   537→            header.innerHTML = html;
   538→        }
   539→
   540→        // Render Gantt chart
   541→        function renderGantt() {
   542→            const content = document.getElementById('ganttContent');
   543→            const svg = document.getElementById('dependencyLines');
   544→
   545→            const totalWidth = DAYS * DAY_WIDTH;
   546→            const totalHeight = TRAIN_COUNT * ROW_HEIGHT;
   547→
   548→            content.style.width = totalWidth + 'px';
   549→            content.style.height = totalHeight + 'px';
   550→
   551→            svg.setAttribute('width', totalWidth);
   552→            svg.setAttribute('height', totalHeight);
   553→
   554→            // Create row backgrounds
   555→            let rowsHtml = '';
   556→            for (let i = 0; i < TRAIN_COUNT; i++) {
   557→                rowsHtml += `<div class="row-bg" style="top: ${i * ROW_HEIGHT}px;"></div>`;
   558→            }
   559→
   560→            // Create grid lines
   561→            let gridHtml = '';
   562→            for (let i = 0; i <= DAYS; i++) {
   563→                const date = new Date(START_DATE);
   564→                date.setDate(date.getDate() + i);
   565→                const dayOfWeek = date.getDay();
   566→                const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
   567→
   568→                if (isWeekend) {
   569→                    gridHtml += `<div class="grid-line weekend" style="left: ${i * DAY_WIDTH}px;"></div>`;
   570→                } else {
   571→                    gridHtml += `<div class="grid-line" style="left: ${i * DAY_WIDTH}px;"></div>`;
   572→                }
   573→            }
   574→
   575→            // Create task cards
   576→            let tasksHtml = '';
   577→            tasks.forEach(task => {
   578→                const x = task.startDay * DAY_WIDTH + 4;
   579→                const y = task.trainIndex * ROW_HEIGHT + 7;
   580→                const width = task.duration * DAY_WIDTH - 8;
   581→
   582→                let classes = `task-card ${task.taskType.type}`;
   583→                if (task.conflict) classes += ' conflict';
   584→
   585→                tasksHtml += `
   586→                    <div class="${classes}"
   587→                         style="left: ${x}px; top: ${y}px; width: ${width}px;"
   588→                         data-task-id="${task.id}">
   589→                        <span class="task-name">${task.taskType.name}</span>
   590→                        <span class="task-duration">${task.duration}d • ${task.taskType.manHours}h</span>
   591→                    </div>
   592→                `;
   593→            });
   594→
   595→            // Create dependency lines
   596→            let linesHtml = '';
   597→            tasks.forEach(task => {
   598→                task.dependencies.forEach(depId => {
   599→                    const depTask = tasks.find(t => t.id === depId);
   600→                    if (depTask) {
   601→                        const x1 = (depTask.startDay + depTask.duration) * DAY_WIDTH;
   602→                        const y1 = depTask.trainIndex * ROW_HEIGHT + ROW_HEIGHT / 2;
   603→                        const x2 = task.startDay * DAY_WIDTH;
   604→                        const y2 = task.trainIndex * ROW_HEIGHT + ROW_HEIGHT / 2;
   605→
   606→                        // Create bezier curve
   607→                        const midX = (x1 + x2) / 2;
   608→
   609→                        linesHtml += `
   610→                            <path d="M ${x1} ${y1} C ${midX} ${y1}, ${midX} ${y2}, ${x2} ${y2}"
   611→                                  fill="none"
   612→                                  stroke="#94a3b8"
   613→                                  stroke-width="2"
   614→                                  stroke-dasharray="4,4"
   615→                                  marker-end="url(#arrowhead)"/>
   616→                        `;
   617→                    }
   618→                });
   619→            });
   620→
   621→            // Add arrowhead marker definition
   622→            svg.innerHTML = `
   623→                <defs>
   624→                    <marker id="arrowhead" markerWidth="10" markerHeight="7"
   625→                            refX="9" refY="3.5" orient="auto">
   626→                        <polygon points="0 0, 10 3.5, 0 7" fill="#94a3b8"/>
   627→                    </marker>
   628→                </defs>
   629→                ${linesHtml}
   630→            `;
   631→
   632→            content.innerHTML = rowsHtml + gridHtml + tasksHtml + svg.outerHTML;
   633→        }
   634→
   635→        // Render minimap
   636→        function renderScrubber() {
   637→            const canvas = document.getElementById('scrubberMinimap');
   638→            const ctx = canvas.getContext('2d');
   639→
   640→            canvas.width = canvas.parentElement.clientWidth;
   641→            canvas.height = 24;
   642→
   643→            const w = canvas.width;
   644→            const h = canvas.height;
   645→
   646→            // Draw mini task representation
   647→            tasks.forEach(task => {
   648→                const x = (task.startDay / DAYS) * w;
   649→                const barWidth = (task.duration / DAYS) * w;
   650→                const y = (task.trainIndex / TRAIN_COUNT) * (h - 4) + 2;
   651→
   652→                ctx.fillStyle = task.taskType.type === 'maintenance' ? '#3b82f6' :
   653→                               task.taskType.type === 'overhaul' ? '#f59e0b' : '#10b981';
   654→                ctx.fillRect(x, y, Math.max(barWidth, 2), 2);
   655→            });
   656→        }
   657→
   658→        // Tooltip handling
   659→        const tooltip = document.getElementById('tooltip');
   660→
   661→        document.getElementById('ganttContent').addEventListener('mousemove', (e) => {
   662→            const taskCard = e.target.closest('.task-card');
   663→
   664→            if (taskCard) {
   665→                const taskId = parseInt(taskCard.dataset.taskId);
   666→                const task = tasks.find(t => t.id === taskId);
   667→
   668→                if (task) {
   669→                    // Update tooltip content
   670→                    document.getElementById('tooltipBadge').textContent = task.taskType.name;
   671→                    document.getElementById('tooltipBadge').className = `tooltip-badge ${task.taskType.type}`;
   672→                    document.getElementById('tooltipTitle').textContent = task.trainId;
   673→
   674→                    const startDate = new Date(START_DATE);
   675→                    startDate.setDate(startDate.getDate() + task.startDay);
   676→                    const endDate = new Date(startDate);
   677→                    endDate.setDate(endDate.getDate() + task.duration);
   678→
   679→                    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
   680→                    document.getElementById('tooltipStart').textContent = `${monthNames[startDate.getMonth()]} ${startDate.getDate()}, ${startDate.getFullYear()}`;
   681→                    document.getElementById('tooltipEnd').textContent = `${monthNames[endDate.getMonth()]} ${endDate.getDate()}, ${endDate.getFullYear()}`;
   682→                    document.getElementById('tooltipDuration').textContent = `${task.duration * 24} hours`;
   683→                    document.getElementById('tooltipManHours').textContent = task.taskType.manHours;
   684→
   685→                    const conflictEl = document.getElementById('tooltipConflict');
   686→                    if (task.conflict) {
   687→                        conflictEl.style.display = 'block';
   688→                        conflictEl.textContent = `⚠ Resource conflict detected`;
   689→                    } else {
   690→                        conflictEl.style.display = 'none';
   691→                    }
   692→
   693→                    // Position tooltip
   694→                    tooltip.style.left = (e.clientX + 15) + 'px';
   695→                    tooltip.style.top = (e.clientY - 10) + 'px';
   696→                    tooltip.classList.add('visible');
   697→                }
   698→            } else {
   699→                tooltip.classList.remove('visible');
   700→            }
   701→        });
   702→
   703→        document.getElementById('ganttContent').addEventListener('mouseleave', () => {
   704→            tooltip.classList.remove('visible');
   705→        });
   706→
   707→        // Initialize
   708→        generateSidebar();
   709→        generateTimeline();
   710→        renderGantt();
   711→        renderScrubber();
   712→
   713→        window.addEventListener('resize', () => {
   714→            renderScrubber();
   715→        });
   716→    </script>
   717→</body>
